  1→/* ── Related Posts Section ── */
  2→
  3→.rp-section {
  4→    margin-top: 0;
  5→    padding-top: 1rem;
  6→    border-top: 1px solid var(--border-light);
  7→    padding-bottom: 5rem;
  8→    max-width: 620px;
  9→    width: 100%;
 10→    padding-left: 24px;
 11→    padding-right: 24px;
 12→    box-sizing: border-box;
 13→}
 14→
 15→.rp-heading {
 16→    display: flex;
 17→    align-items: center;
 18→    gap: 0.4rem;
 19→    font-family: var(--font-ui);
 20→    font-size: 0.7rem;
 21→    font-weight: 700;
 22→    letter-spacing: 0.06rem;
 23→    text-transform: uppercase;
 24→    background: linear-gradient(135deg, var(--accent-amber), var(--accent-purple));
 25→    -webkit-background-clip: text;
 26→    -webkit-text-fill-color: transparent;
 27→    background-clip: text;
 28→    margin: 0 0 1rem 0;
 29→}
 30→
 31→.rp-heading-icon {
 32→    width: 15px;
 33→    height: 15px;
 34→    flex-shrink: 0;
 35→    color: var(--accent-amber);
 36→    filter: drop-shadow(0 0 3px rgba(212, 168, 83, 0.35));
 37→    animation: rp-icon-pulse 3s ease-in-out infinite;
 38→}
 39→
 40→@keyframes rp-icon-pulse {
 41→    0%, 100% { opacity: 0.8; transform: scale(1); }
 42→    50% { opacity: 1; transform: scale(1.1); }
 43→}
 44→
 45→.rp-heading::after {
 46→    content: '';
 47→    flex: 1;
 48→    height: 1px;
 49→    background: linear-gradient(90deg, var(--accent-amber), transparent);
 50→    opacity: 0.3;
 51→}
 52→
 53→/* ── Card Grid ── */
 54→
 55→.rp-grid {
 56→    display: flex;
 57→    flex-direction: column;
 58→    gap: 0.625rem;
 59→}
 60→
 61→/* ── Card ── */
 62→
 63→.rp-card {
 64→    display: flex;
 65→    align-items: stretch;
 66→    border-radius: 12px;
 67→    background: var(--bg-card);
 68→    border: 1px solid var(--border-card);
 69→    cursor: pointer;
 70→    overflow: hidden;
 71→    transition: box-shadow 0.25s ease, transform 0.25s ease, border-color 0.25s ease;
 72→}
 73→
 74→.rp-card:hover {
 75→    box-shadow: 0 4px 18px rgba(0, 0, 0, 0.06);
 76→    transform: translateY(-1px);
 77→    border-color: rgba(212, 168, 83, 0.2);
 78→}
 79→
 80→/* ── Accent Line ── */
 81→
 82→.rp-card-accent {
 83→    width: 3.5px;
 84→    flex-shrink: 0;
 85→    background: linear-gradient(180deg, var(--accent-purple), rgba(196, 148, 62, 0.5));
 86→    border-radius: 3px 0 0 3px;
 87→    transition: opacity 0.3s ease;
 88→}
 89→
 90→/* ── Card Content ── */
 91→
 92→.rp-card-content {
 93→    flex: 1;
 94→    padding: 0.75rem 0.875rem;
 95→    min-width: 0;
 96→}
 97→
 98→.rp-card-title {
 99→    font-family: var(--font-serif);
100→    font-size: 0.875rem;
101→    font-weight: 500;
102→    color: var(--text-primary);
103→    margin: 0 0 0.375rem 0;
104→    line-height: 1.35;
105→    display: -webkit-box;
106→    -webkit-line-clamp: 2;
107→    -webkit-box-orient: vertical;
108→    overflow: hidden;
109→}
110→
111→.rp-card-excerpt {
112→    font-size: 0.78rem;
113→    color: var(--text-muted);
114→    line-height: 1.4;
115→    margin: 0 0 0.375rem 0;
116→    display: -webkit-box;
117→    -webkit-line-clamp: 1;
118→    -webkit-box-orient: vertical;
119→    overflow: hidden;
120→}
121→
122→.rp-card-meta {
123→    display: flex;
124→    align-items: center;
125→    justify-content: space-between;
126→    gap: 0.5rem;
127→}
128→
129→.rp-card-author {
130→    display: flex;
131→    align-items: center;
132→    gap: 0.375rem;
133→    min-width: 0;
134→}
135→
136→.rp-card-avatar {
137→    width: 22px;
138→    height: 22px;
139→    border-radius: 50%;
140→    object-fit: cover;
141→    flex-shrink: 0;
142→}
143→
144→.rp-card-avatar-placeholder {
145→    background: var(--bg-hover);
146→    border: 1px solid var(--border-light);
147→}
148→
149→/* ── Avatar Ring Badge ── */
150→
151→.rp-card-avatar-container {
152→    display: flex;
153→    align-items: center;
154→    justify-content: center;
155→    width: fit-content;
156→    height: fit-content;
157→    border-radius: 50%;
158→    flex-shrink: 0;
159→}
160→
161→.rp-avatar-ring-legend {
162→    border: 2px solid #FFD700;
163→    box-shadow: 0 0 8px 1px rgba(255, 215, 0, 0.3);
164→}
165→
166→.rp-avatar-ring-og {
167→    border: 2px solid #9B59FF;
168→    box-shadow: 0 0 8px 1px rgba(155, 89, 255, 0.3);
169→}
170→
171→.rp-card-name {
172→    font-size: 0.75rem;
173→    color: var(--text-secondary);
174→    white-space: nowrap;
175→    overflow: hidden;
176→    text-overflow: ellipsis;
177→    max-width: 140px;
178→}
179→
180→.rp-card-date {
181→    font-size: 0.7rem;
182→    color: var(--text-muted);
183→    white-space: nowrap;
184→    flex-shrink: 0;
185→}
186→
187→/* ── Skeleton Loading ── */
188→
189→.rp-skeleton-container {
190→    display: flex;
191→    flex-direction: column;
192→    gap: 0.625rem;
193→}
194→
195→.rp-skeleton-card {
196→    display: flex;
