203→}
204→
205→.rp-skeleton-accent {
206→    width: 3.5px;
207→    flex-shrink: 0;
208→    background: var(--bg-hover);
209→    animation: rp-shimmer 1.5s ease-in-out infinite;
210→}
211→
212→.rp-skeleton-content {
213→    flex: 1;
214→    padding: 0.75rem 0.875rem;
215→    display: flex;
216→    flex-direction: column;
217→    justify-content: center;
218→    gap: 0.5rem;
219→}
220→
221→.rp-skeleton-title {
222→    height: 12px;
223→    width: 65%;
224→    border-radius: 4px;
225→    background: var(--bg-hover);
226→    animation: rp-shimmer 1.5s ease-in-out infinite;
