237→}
238→
239→.rp-skeleton-meta {
240→    display: flex;
241→    align-items: center;
242→    gap: 0.375rem;
243→}
244→
245→.rp-skeleton-avatar {
246→    width: 22px;
247→    height: 22px;
248→    border-radius: 50%;
249→    background: var(--bg-hover);
250→    animation: rp-shimmer 1.5s ease-in-out infinite;
